// ── Parse and validate Groq response ────────────────────
const groqResponse = $input.first().json;
const ticketData = $('Code: Build Classification Prompt').item.json;

let classification;
try {
  const content = groqResponse.choices[0].message.content;
  classification = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  throw new Error(`Failed to parse Groq response as JSON: ${e.message}`);
}

// Validate expected fields
const validCategories = ['Billing', 'Technical Support', 'Sales', 'Security', 'Account Management'];
const validPriorities = ['Low', 'Medium', 'High', 'Critical'];

if (!validCategories.includes(classification.category)) {
  throw new Error(`Invalid category from AI: '${classification.category}'. Expected one of: ${validCategories.join(', ')}`);
}
if (!validPriorities.includes(classification.priority)) {
  throw new Error(`Invalid priority from AI: '${classification.priority}'. Expected one of: ${validPriorities.join(', ')}`);
}
if (typeof classification.confidence !== 'number' || classification.confidence < 0 || classification.confidence > 100) {
  throw new Error(`Invalid confidence value: ${classification.confidence}`);
}

return [{
  json: {
    ticket_id:    ticketData.ticket_id,
    name:         ticketData.name,
    email:        ticketData.email,
    subject:      ticketData.subject,
    message:      ticketData.message,
    category:     classification.category,
    priority:     classification.priority,
    confidence:   classification.confidence,
    reasoning:    classification.reasoning,
    model_used:   groqResponse.model,
    raw_response: JSON.stringify(groqResponse)
  }
}];
